import json

# Load funding data
funding_var = locals()['var_functions.query_db:4']
if isinstance(funding_var, str):
    with open(funding_var, 'r') as f:
        funding_data = json.load(f)
else:
    funding_data = funding_var

# Load civic documents
civic_var = locals()['var_functions.query_db:11']
if isinstance(civic_var, str):
    with open(civic_var, 'r') as f:
        civic_docs = json.load(f)
else:
    civic_docs = civic_var

# Create funding map
funding_map = {}
for rec in funding_data:
    funding_map[rec['Project_Name']] = int(rec['Amount'])

# Find design projects from civic docs
found_projects = set()

for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.split('\n')
    in_design = False

    for line in lines:
        line = line.strip()

        if 'Capital Improvement Projects' in line and 'Design' in line:
            in_design = True
            continue

        if in_design and 'Construction' in line:
            break
        if in_design and 'Not Started' in line:
            break

        if in_design and line:
            name = line.strip('â€¢â€‘- ').strip()
            if name in funding_map:
                if funding_map[name] > 50000:
                    found_projects.add(name)

count = len(found_projects)
print('__RESULT__:')
print(json.dumps(count))

